('Blue Crush', 'blue-crush', 'sativa', 19.2, 0.3, array['tingly', 'talkative', 'uplifted', 'hungry']::text[], array['spicy', 'skunk', 'tropical']::text[], array['linalool', 'limonene', 'myrcene']::text[], 'moderate', 10, '450-550 g/m²', '500-650 g/plant', 'Blue Crush — A sativa prized for its energizing, cerebral lift that suits daytime creativity and social sessions. Expect spicy, skunk, tropical flavors with dominant linalool, most often leaving users feeling tingly and talkative.')
